342	export const useFlashSystemSchema = (): Yup.ObjectSchema<{}> => {
343	  const { t } = useCustomTranslation();
344	
345	  const { odfNamespace } = useODFNamespaceSelector();
346	
347	  // Non-RHCS StorageSystems are only created in ODF install namespace
348	  const [secretData, secretLoaded, secretLoadError] =
349	    useSafeK8sList<SecretKind>(SecretModel, odfNamespace);
350	  const [flashSystemData, flashSystemLoaded, flashSystemLoadError] =
351	    useK8sList<IBMFlashSystemKind>(IBMFlashSystemModel);
352	
353	  const dataLoaded = flashSystemLoaded && secretLoaded;
354	  const dataLoadError = flashSystemLoadError || secretLoadError;
355	
356	  return React.useMemo(() => {
357	    const existingFlashSystemSecretNames =
358	      dataLoaded && !dataLoadError
359	        ? flashSystemData?.map((data) => getFlashSystemSecretName(data))
360	        : [];
361	
362	    const existingSecretManagementAddresses =
363	      existingFlashSystemSecretNames.map((secretName) => {
364	        const secret = secretData?.find(
365	          (secret) =>
366	            getName(secret) === secretName &&
367	            getNamespace(secret) === odfNamespace
368	        );
369	        return atob(getSecretManagementAddress(secret));
370	      });
371	
372	    return Yup.object({
373	      'endpoint-input': Yup.string()
374	        .required()
375	        .test(
376	          'ip-address',
377	          t('The endpoint is not a valid IP address'),
378	          (value: string) => isValidIP(value)
379	        )
380	        .test(
381	          'unique-ip-address',
382	          t('The IP address is already registered'),
383	          (value: string) =>
384	            !isIPRegistered(value, existingSecretManagementAddresses)
385	        ),
386	      'username-input': Yup.string().required(),
387	      'password-input': Yup.string().required(),
388	      'poolname-input': Yup.string().required(),
389	    });
390	  }, [secretData, flashSystemData, dataLoaded, dataLoadError, odfNamespace, t]);
391	};
392	
393	export const createFlashSystemPayload: CreatePayload<FlashSystemState> = ({
394	  systemName,
395	  state,
396	  namespace,
397	  storageClassName,
398	}) => {
399	  const defaultFilesystem = 'ext4';
400	  const defaultVolumeMode = 'thick';
401	  const defaultVolumePrefix = 'odf';
402	
403	  const IBMFlashSystemTemplate: IBMFlashSystemKind = {
404	    apiVersion: getAPIVersionForModel(IBMFlashSystemModel),
405	    kind: IBMFlashSystemModel.kind,
406	    metadata: {
407	      name: systemName,
408	      namespace,
409	    },
410	    spec: {
411	      name: systemName,
412	      insecureSkipVerify: true,
413	      secret: {
414	        name: systemName,
415	        namespace,
416	      },
417	      defaultPool: {
418	        poolName: state.poolname,
419	        storageclassName: storageClassName,
420	        spaceEfficiency: state.volmode ? state.volmode : defaultVolumeMode,
421	        fsType: defaultFilesystem,
422	        volumeNamePrefix: defaultVolumePrefix,
423	      },
424	    },
425	  };
426	
427	  const flashSystemPayload = {
428	    model: IBMFlashSystemModel,
429	    payload: IBMFlashSystemTemplate,
430	  };
431	
432	  const storageSecretTemplate: SecretKind = {
433	    apiVersion: getAPIVersionForModel(SecretModel),
434	    stringData: {
435	      management_address: state.endpoint,
436	      password: state.password,
437	      username: state.username,
438	    },
439	    kind: 'Secret',
440	    metadata: {
441	      name: systemName,
442	      namespace,
443	    },
444	    type: 'Opaque',
445	  };
446	
447	  const secretPayload = {
448	    model: SecretModel,
449	    payload: storageSecretTemplate,
450	  };
451	
452	  return [secretPayload, flashSystemPayload];
453	};

