342	export const useFlashSystemSchema = (): Yup.ObjectSchema<{}> => {
343	  const { t } = useCustomTranslation();
344	
345	  const { odfNamespace } = useODFNamespaceSelector();
346	
347	  // Non-RHCS StorageSystems are only created in ODF install namespace
348	  const [secretData, secretLoaded, secretLoadError] =
349	    useSafeK8sList<SecretKind>(SecretModel, odfNamespace);
350	  const [flashSystemData, flashSystemLoaded, flashSystemLoadError] =
351	    useK8sList<IBMFlashSystemKind>(IBMFlashSystemModel);
352	
353	  const dataLoaded = flashSystemLoaded && secretLoaded;
354	  const dataLoadError = flashSystemLoadError || secretLoadError;
355	
356	  return React.useMemo(() => {
357	    const existingFlashSystemSecretNames =
358	      dataLoaded && !dataLoadError
359	        ? flashSystemData?.map((data) => getFlashSystemSecretName(data))
360	        : [];
361	
362	    const existingSecretManagementAddresses =
363	      existingFlashSystemSecretNames.map((secretName) => {
364	        const secret = secretData?.find(
365	          (secret) =>
366	            getName(secret) === secretName &&
367	            getNamespace(secret) === odfNamespace
368	        );
369	        return atob(getSecretManagementAddress(secret));
370	      });
371	
372	    return Yup.object({
373	      'endpoint-input': Yup.string()
374	        .required()
375	        .test(
376	          'ip-address',
377	          t('The endpoint is not a valid IP address'),
378	          (value: string) => isValidIP(value)
379	        )
380	        .test(
381	          'unique-ip-address',
382	          t('The IP address is already registered'),
383	          (value: string) =>
384	            !isIPRegistered(value, existingSecretManagementAddresses)
385	        ),
386	      'username-input': Yup.string().required(),
387	      'password-input': Yup.string().required(),
388	      'poolname-input': Yup.string().required(),
389	    });
390	  }, [secretData, flashSystemData, dataLoaded, dataLoadError, odfNamespace, t]);
391	};
