393	export const createFlashSystemPayload: CreatePayload<FlashSystemState> = ({
394	  systemName,
395	  state,
396	  namespace,
397	  storageClassName,
398	}) => {
399	  const defaultFilesystem = 'ext4';
400	  const defaultVolumeMode = 'thick';
401	  const defaultVolumePrefix = 'odf';
402	
403	  const IBMFlashSystemTemplate: IBMFlashSystemKind = {
404	    apiVersion: getAPIVersionForModel(IBMFlashSystemModel),
405	    kind: IBMFlashSystemModel.kind,
406	    metadata: {
407	      name: systemName,
408	      namespace,
409	    },
410	    spec: {
411	      name: systemName,
412	      insecureSkipVerify: true,
413	      secret: {
414	        name: systemName,
415	        namespace,
416	      },
417	      defaultPool: {
418	        poolName: state.poolname,
419	        storageclassName: storageClassName,
420	        spaceEfficiency: state.volmode ? state.volmode : defaultVolumeMode,
421	        fsType: defaultFilesystem,
422	        volumeNamePrefix: defaultVolumePrefix,
423	      },
424	    },
425	  };
426	
427	  const flashSystemPayload = {
428	    model: IBMFlashSystemModel,
429	    payload: IBMFlashSystemTemplate,
430	  };
431	
432	  const storageSecretTemplate: SecretKind = {
433	    apiVersion: getAPIVersionForModel(SecretModel),
434	    stringData: {
435	      management_address: state.endpoint,
436	      password: state.password,
437	      username: state.username,
438	    },
439	    kind: 'Secret',
440	    metadata: {
441	      name: systemName,
442	      namespace,
443	    },
444	    type: 'Opaque',
445	  };
446	
447	  const secretPayload = {
448	    model: SecretModel,
449	    payload: storageSecretTemplate,
450	  };
451	
452	  return [secretPayload, flashSystemPayload];
453	};

